"""
MKT Christ Commentary — 1 Samuel chapters 22–24 (fill)
Run: python3 scripts/zc-christ-1samuel-22-24-fill.py

Fills gaps: v2/v20 of ch22, v16 of ch23, v6/v15 of ch24 already present.

Christological typology:
- Ch22: Cave of Adullam as locus of the rejected anointed gathering outcasts
  (v2 present — basis for Matt 9:12-13); Doeg/Nob massacre as type of
  Herod's slaughter of innocents near the rejected king (Matt 2:16-18);
  David taking responsibility for the priests' death (v22) prefigures
  Christ bearing others' death-consequences
- Ch23: Prophetic guidance via ephod as type of Spirit-led mission;
  Jonathan's 'he strengthened his hand in God' (v16 present) as
  type of Spirit-strengthening (Acts 9:31); covenant of surrender —
  Jonathan yields claim to throne to David, type of John Baptist (John 3:30)
- Ch24: En Gedi — non-retaliation against anointed persecutor; David's
  anti-grasping posture (v6 present) as type of Phil 2:6-8; divine judgment
  appeal (v15 present) as model of patient suffering under injustice (1 Pet 2:23)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge without overwriting existing entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

SAM1 = {
  "22": {
    "1": "<p>David's flight from Gath (ch21) brings him to the cave of Adullam: <em>wayyāḇōʾ dāwid šammāh wayyiśmᵉʿû ʾeḥāyw wᵉḵol bêt ʾāḇîw wayyērᵉdû ʾēlāyw šammāh</em> — his brothers and all his father's household come down to him. The rejected anointed becomes the gathering-point for his family — those who had overlooked him (cf. 16:11) now shelter with him. Adullam was a cave in the Shephelah near the Philistine border — liminal territory between Israel and its enemies. The cave as hideout of the anointed-in-exile becomes a recurrent type: Elijah at the Horeb cave (1 Kgs 19:9), the cave-dwelling saints of Heb 11:38, and ultimately the garden-tomb from which the risen Christ emerges as the Anointed-no-longer-hidden.</p>",
    "3": "<p>David leaves his parents at Mizpeh of Moab with the king: <em>yēṣeʾ ʾāḇî wᵉʾimmî nāʾ ʾittᵉḵem ʿad ʾăšer ʾēdaʿ mah-yāʿăśeh lî ʾĕlōhîm</em> — let my father and mother come out with you until I know what God will do for me. The deposit of his parents in Moab — the homeland of his great-grandmother Ruth — is both practical and symbolic: David preserves the family line by removing it from Saul's reach. The uncertainty expressed (<em>ʿad ʾăšer ʾēdaʿ</em>, until I know) models dependence on divine disclosure rather than human planning. Jesus's similar entrusting of his mother to the Beloved Disciple from the cross (John 19:26-27) has the same protective logic.</p>",
    "4": "<p>David's parents stay with the king of Moab all the days David was in the stronghold (<em>bammᵉṣûdāh</em>). The Moabite interlude recalls David's ancestry (Ruth 4:22) and demonstrates that YHWH's providential care for the messianic line runs through unlikely nations. The exile of the anointed king's family among foreign peoples — preserved and then restored — becomes part of the broader pattern of messianic preservation through hostile territory.</p>",
    "5": "<p>The prophet Gad instructs David: <em>lōʾ tēšeḇ baṣṣᵉdāh lēḵ ûḇāʾtā lᵉḵā ʾereṣ yᵉhûdāh</em> — do not remain in the stronghold; go into the land of Judah. The prophetic guidance directs the anointed king back into his own territory despite the danger. This tension — divine command to return to the dangerous homeland — is the pattern of the messianic mission: <em>he came to his own, and his own did not receive him</em> (John 1:11). David's obedience to prophetic direction despite personal risk foreshadows Jesus's willingness to enter Jerusalem knowing what awaited him.</p>",
    "6": "<p>Saul hears that David and his men have been discovered: <em>wayyēšeḇ baGiḇʿāh taḥat hāʾēšel bāRāmāh wᵉḥănîtô bᵉyādô wᵉḵol ʿăḇādāyw niṣṣāḇîm ʿālāyw</p> — he sits at Gibeah under the tamarisk tree with his spear in hand and his officials standing around him. The spear in Saul's hand is his signature symbol throughout Samuel — it appears at moments of murderous rage against David (18:11; 19:9) and becomes a metonym for the persecutor king. The rejected king's pursuer sits armed and surrounded by courtiers; the true king camps in wilderness caves. The power differential is visible and overwhelming.</p>",
    "7": "<p>Saul's speech to his Benjaminite officials: <em>šimᵉʿû nāʾ bᵉnê Yᵉmînî gam-lᵉḵulleḵem yittēn ben-Yišay śādôt ûkᵉrāmîm lᵉḵulleḵem yāśîm śārê ʾălāpîm wᵉśārê mēʾôt</em> — will the son of Jesse give you all fields and vineyards? Will he make you commanders? The appeal to tribal self-interest — patronage from the ruling house — is Saul's mechanism for loyalty. He frames David as a threat to Benjaminite privilege. The demagogue's appeal to material self-interest as a substitute for justice recurs throughout sacred history.</p>",
    "8": "<p>Saul accuses his men of conspiracy (<em>qᵉšarttem ʿālay</em>): <em>waʾên gōleh ʾet ʾāznî bᵉḵaret bᵉnî ʿim ben Yišay</em> — not one of you has informed me that my son Jonathan has made a covenant with the son of Jesse. The rage at Jonathan's covenant with David — the heir making a personal alliance with the rival — expresses Saul's deepest political fear. Jonathan's covenant is in fact the prophetic reality: the true king and the yielding heir have made their peace before the transfer of power happens.</p>",
    "9": "<p>Doeg the Edomite (cf. 21:7) speaks up: <em>rāʾîtî ʾet ben Yišay bāʾ Nōḇāh ʾel ʾAḥîmelek ben ʾĂḥîṭûḇ</em> — I saw the son of Jesse come to Ahimelech at Nob. Doeg's denunciation is technically accurate but strategically treacherous. He was present when David received the bread and the sword (21:7); his silence then enabled David's provision; his speech now enables the massacre. The informer who reports truth for murderous ends embodies a type of betrayal — accurate testimony used to destroy the innocent — that recurs in the NT: the witnesses at Jesus's trial (Mark 14:57-59) who quote his words in distorted context.</p>",
    "10": "<p>Doeg reports Ahimelech's actions: the priest inquired of YHWH for David (<em>wayyišʾal lô baYHWH</em>), gave him provisions, and gave him the sword of Goliath. The three acts — prophetic inquiry, provision of bread, provision of the weapon — correspond exactly to the priestly functions David sought (21:2-9). Ahimelech had been deceived by David's false claim of a royal mission but had acted in good faith. Doeg's report transforms acts of priestly hospitality into evidence of treason.</p>",
    "11": "<p>Saul summons Ahimelech and all his father's house — the entire priestly family of Nob (<em>kol bêt ʾāḇîw hakkōhănîm ʾăšer bᵉNōḇ</em>). The summoning of the entire priestly community to stand before the king foreshadows the kangaroo-court dynamic: Saul has decided on the verdict before hearing the case. The power of the state arrayed against the priestly community for complicity with the rejected anointed is the structural parallel to the Sanhedrin gathering against Jesus and his followers.</p>",
    "12": "<p>Saul interrogates Ahimelech: <em>šmaʿ nāʾ ben ʾĂḥîṭûḇ</em> — hear now, son of Ahitub. <em>wayyōʾmer hinnēnî ʾădōnî</em> — and he said, here I am, my lord. The priest's readiness to answer recalls the prophetic vocation summons (<em>hinnēnî</em>, here I am — cf. Samuel's response to YHWH in 3:4). Ahimelech presents himself openly to power. His willingness to stand before the hostile king contrasts with the witnesses who fled — the pattern of those who do not fear the earthly power because they serve a higher one.</p>",
    "13": "<p>Saul accuses Ahimelech: <em>lāmmāh qᵉšarttem ʿālay ʾattāh ûḇen Yišay lātît lᵉḵā leḥem wᵉḥereḇ</em> — why have you conspired against me, you and the son of Jesse, by giving him bread and a sword? The charge of conspiracy (<em>qāšar</em>) is the same applied to Jonathan's covenant (v8). Saul sees every relationship that does not serve his power as treason. The priest's priestly act — giving the bread of the Presence and a weapon to someone he believed was on royal business — is reframed as military conspiracy.</p>",
    "14": "<p>Ahimelech's defense: <em>ûmî ḇᵉḵol ʿăḇādêḵā kaḏāwid neʾĕmān wᵉḥātān hammélek wᵉsār ʾel mišmaʿtêḵā</em> — who among all your servants is as faithful as David, the king's son-in-law, captain of your bodyguard? Ahimelech argues from David's evident loyalty — his status as royal son-in-law, captain. The defense appeals to David's track record rather than to priestly law. The priest does not know David has been condemned; he is defending a man on the basis of that man's character and prior relationship with the king.</p>",
    "15": "<p><em>hāyôm hiḥillōtî lišʾol lô bēlōhîm ḥālîlāh lî</em> — was today the first time I inquired of God for him? Far from it! Ahimelech protests his ongoing priestly service to David. He concludes: <em>ʾal yāśem hammélek bᵉʿaḇdô dāḇār bᵉḵol bêt ʾāḇî kî lōʾ yādaʿ ʿaḇdᵉḵā bᵉḵol zōʾt dāḇār qāṭōn wᵉgādôl</em> — do not impute anything to your servant or to all my father's house, for your servant knew nothing of all this, small or great. The priestly innocence-claim before the king parallels Jesus's silence before Pilate (Matt 27:14) — the innocent refusing to defend themselves against unjust power while still making clear their integrity.</p>",
    "16": "<p>Saul's verdict: <em>môt tāmût ʾAḥîmelek ʾattāh wᵉḵol bêt ʾāḇîḵā</em> — you shall surely die, Ahimelech, you and all your father's house. The death sentence on the entire priestly household is collective punishment: guilt-by-association extended to family. The legal structure of Israel prohibited collective punishment (Deut 24:16), but Saul's paranoid monarchy overrides law. The condemned priest community parallels the early Christian martyrs condemned by state authority for association with the true king.</p>",
    "17": "<p>Saul orders his guards (<em>rāṣîm</em>, runners) to kill the priests of YHWH: <em>pᵉnû wᵉhāmîtû kōhănê YHWH kî gam yādām ʿim dāwid</em> — because their hand also is with David. The guards refuse (<em>lōʾ ʾāḇû ʿăḇadê hammélek lišlōaḥ ʾet yādām lipgōʿ bᵉḵōhănê YHWH</em>) — they would not stretch out their hand against the priests of YHWH. The guards' refusal is a sign of remaining moral conscience even within the apostate court. There is always a remnant who will not cross the line of sacrilege, even under direct royal command.</p>",
    "18": "<p>Doeg the Edomite carries out the massacre: <em>wayyāsob Dōʾeg hāʾĕdōmî wayyipgaʿ hûʾ bakkōhănîm wayyāmot bayyôm hahûʾ šᵉmōnîm wᵉḥămiššāh ʾîš nōśēʾ ʾēpôd bād</em> — Doeg the Edomite turned and fell upon the priests, eighty-five men who wore the linen ephod. The specific detail — eighty-five priests wearing the ephod — emphasizes that these were serving ministers slaughtered in priestly garb. The ephod (sign of their office) does not protect them; the murderer's foreignness (Edomite) contrasts with the Israelite guards' refusal. The outsider does what no Israelite was willing to do. The slaughter of the priestly community nearest to the fugitive anointed echoes in Matthew's Herod narrative: the innocents slaughtered near the infant messianic king (Matt 2:16-18) follow the Adullam-and-Nob structural pattern.</p>",
    "19": "<p><em>wᵉʾet Nōḇ ʿîr hakkōhănîm hikkāh leḥad haḥereḇ mēʾîš wᵉʿad ʾiššāh mēʿôlēl wᵉʿad yônēq ûšôr waḥămôr wᵉśeh leḥad haḥereḇ</em> — and Nob, the city of priests, he struck with the edge of the sword, both men and women, children and nursing infants, oxen, donkeys, and sheep — with the edge of the sword. The totality of the destruction — applying the <em>ḥerem</em>-like formula to a priestly city — inverts the holy-war command: Saul failed to apply this formula to Amalek (ch15) as commanded and now applies it to YHWH's own priests. The persecutor's violence, misdirected and self-serving, destroys the holy community while sparing the enemy.</p>",
    "21": "<p>Abiathar tells David that Saul has killed the priests of YHWH. David's response in v22 takes responsibility. This verse establishes the connection: the only surviving priest, carrying the ephod, finds refuge with the rejected anointed. Abiathar's flight to David creates the structural fulfillment of priestly and royal alignment — the legitimate heir of the priestly line joins the legitimate heir of the royal line, reconstituting the proper order in exile.</p>",
    "22": "<p><em>wayyōʾmer dāwid lᵉʾAḇyātār yādaʿtî bayyôm hahûʾ kî šam Dōʾeg hāʾĕdōmî kî haggēd yaggîd lᵉŠāʾûl ʾānōḵî sabhōtî bᵉḵol nepeš bêt ʾāḇîḵā</em> — I knew on that day when Doeg the Edomite was there that he would surely tell Saul. I have caused the death of all the persons of your father's house. David's self-accusation — <em>ʾānōḵî sabbōtî</em>, I have turned about, caused this — is a remarkable acceptance of moral responsibility for consequences he did not directly cause. His deception of Ahimelech (21:2) triggered the chain; he owns that. This willingness to bear responsibility for the innocent deaths that resulted from his decisions points to the pattern fully expressed in Christ: <em>he bore our sins in his body on the tree</em> (1 Pet 2:24). The rejected anointed takes on the weight of deaths he did not intend but whose chain he initiated.</p>",
    "23": "<p><em>šeḇ ʾittî ʾal tîrāʾ kî ʾăšer yᵉḇaqqēš ʾet napšî yᵉḇaqqēš ʾet napšeḵā kî mišmeret ʾattāh ʿimmādî</em> — stay with me, do not fear; for whoever seeks my life seeks yours also; with me you shall be in safekeeping. David offers the survivor of the Nob massacre his own protection — the fugitive king sheltering the refugee priest. <em>mišmeret</em> (safekeeping, guard) is the same word used for the priestly vigil over the tabernacle (Num 3:28). The king's protection of the priest reverses the royal-priestly relationship: normally the king relies on the priest's intercession; here the king shelters the priest in mortal danger.</p>"
  },
  "23": {
    "1": "<p>David hears that the Philistines are attacking Keilah and looting the threshing floors (<em>šōsîm ʾet haggōrānôt</em>). His instinct is to fight — to protect a Judean city even while he is a fugitive from Saul. The willingness of the anointed-but-not-yet-enthroned king to act in kingly defense of the people anticipates the pattern of servant-kingship: David exercises royal protection before possessing royal authority. Jesus heals and feeds people before the cross establishes his throne.</p>",
    "2": "<p>David inquires of YHWH through the ephod: <em>hāʾēlēḵ wᵉhikkîtî bappᵉlištîm hāʾēlleh</em> — shall I go and strike these Philistines? The answer is yes: <em>lēḵ wᵉhikkîtā bappᵉlištîm wᵉhôšaʿtā ʾet Qᵉʿîlāh</em> — go, strike the Philistines and save Keilah. The ephod-consultation sequence (go → inquiry → divine confirmation → action) establishes Spirit-guided mission. The Spirit's direction of the anointed's mission is the OT prototype for the NT's Spirit-led apostolic mission (Acts 13:2-4; 16:6-10).</p>",
    "3": "<p>David's men resist: <em>hinnēh ʾănaḥnû pōh bîhûdāh yᵉrēʾîm ûmah kî nēlēḵ Qᵉʿîlāh ʾel maʿarḵôt Pᵉlištîm</em> — we are afraid here in Judah; how much more if we go to Keilah against the Philistine forces? The disciples' fear — they can barely survive where they are, let alone take on a new fight — is the natural human calculation against costly obedience. David inquires again (v4) and receives the same answer: <em>qûm rēd Qᵉʿîlāh kî ʾānōḵî nōtēn ʾet Pᵉlištîm bᵉyādeḵā</em> — rise, go down to Keilah, for I am giving the Philistines into your hand.</p>",
    "4": "<p>The double inquiry of YHWH (vv2-4) establishes the model of persistent prophetic consultation. The first confirmation overcomes theological doubt; the second overcomes human fear. The pattern — divine command, human hesitation, recommitment — occurs throughout the prophetic tradition (Jonah 3:1-3, repeating the commission after Jonah's flight) and in the disciples' commissioning (Acts 1:8 → Acts 8:1 → the actual scattering that produces the mission).</p>",
    "5": "<p>David and his men go to Keilah, fight the Philistines, and rescue the city: <em>wayyôšaʿ dāwid ʾet yōšᵉḇê Qᵉʿîlāh</em> — David saved the inhabitants of Keilah. The verb <em>yāšaʿ</em> (save) applied to David's military rescue recurs as the theological signature of the anointed: David is a <em>yôšîaʿ</em>, a deliverer. The messianic name Yeshua/Jesus embeds this deliverer-function in the person of the ultimate Anointed (<em>hûʾ yôšîaʿ ʾet ʿammô mēḥaṭṭōʾtêhem</em>, Matt 1:21).</p>",
    "6": "<p>Abiathar the priest, who brought the ephod to David at Keilah, is the direct link between the Nob massacre's survivor and the ongoing prophetic guidance of the fugitive king. The ephod — the priestly instrument of divine inquiry — is now with the true king rather than in the destroyed priestly city. The transfer of the ephod from Nob to David's camp fulfills the prophetic sentence against the house of Eli (2:27-36): the priestly line that served Saul is destroyed; the ephod that enables divine guidance migrates to the true king.</p>",
    "7": "<p>Saul hears David is in Keilah and concludes that God has delivered him into his hand: <em>nāḵar ʾōtô ʾĕlōhîm bᵉyādî kî nisgār lāḇōʾ bᵉʿîr daltayim ûḇᵉrîaḥ</em> — God has given him into my hand, for he has shut himself in by entering a city with gates and bars. Saul's misreading of providence — interpreting David's presence in a walled city as divine gift rather than divine trap for Saul himself — demonstrates the persecutor's theological confusion. He sees confirmation of his purpose where there is actually the working out of his judgment.</p>",
    "8": "<p>Saul summons all the people to go down to Keilah and besiege David: the full military apparatus of the king marshaled against a single fugitive saving a Judean city. The disproportion is the narrative's theological point: the illegitimate king's full power pursues the legitimate king who just rescued the city the pursuer should have protected.</p>",
    "9": "<p>David, knowing Saul's evil design (<em>kî ʿālāyw Šāʾûl mᵉḥārēš hārāʿāh</em>), says to Abiathar: bring the ephod. The knowledge of the evil plan, obtained through some prophetic channel before the full inquiry, drives the consultation. The sequence — knowledge of threat → prophetic inquiry → divine answer → escape — is the pattern of Jesus's post-resurrection appearances: he knows what the disciples need before they ask (John 21:6).</p>",
    "10": "<p>David's prayer: <em>YHWH ʾĕlōhê yiśrāʾēl šāmōaʿ šāmaʿ ʿaḇdᵉḵā kî šāmōaʿ šāmaʿ Šāʾûl mᵉḇaqqēš lāḇôʾ ʾel Qᵉʿîlāh lᵉšaḥēt lāʿîr bᵉʿăḇūrî</em> — YHWH God of Israel, your servant has heard that Saul seeks to come to Keilah to destroy the city on my account. David's prayer places his own welfare last — his primary concern is the destruction of Keilah on his account. The anointed takes on responsibility for the city's jeopardy rather than merely seeking his own escape. This other-centered framing of the prayer defines the messianic vocation.</p>",
    "11": "<p>The double question to YHWH: will the men of Keilah surrender David to Saul? Will Saul come down? YHWH answers both: <em>yāred</em> — he will come down; <em>yasgîrû</em> — they will surrender you. The answer is a prophetic disclosure of future human decisions — YHWH knows what Keilah will choose before they choose it. The divine foreknowledge of human betrayal (not coercion, but foreknowledge) parallels Jesus's prediction of Judas's betrayal (John 13:21) and Peter's denial (Matt 26:34) — the omniscient Anointed knows who will betray him and yet proceeds.</p>",
    "12": "<p>David and his men depart: the city of Keilah is rescued but will not protect its rescuer. The beneficiaries of the anointed's salvation repay with betrayal. This pattern — saving those who will subsequently abandon you — is fundamental to the Davidic-messianic vocation. Jesus saves and is abandoned: <em>they all fled</em> (Mark 14:50). The anointed's salvation does not depend on the gratitude of the saved.</p>",
    "13": "<p>David and about 600 men depart from Keilah. The number 600 is significant: it matches the number of Saul's initial fighting force (13:15) and the Danite warriors (Judg 18:11). The fugitive army is a mirror-kingdom — the true king with a fighting force equal to the recognized king's initial muster. When Saul hears David has escaped Keilah, the campaign is abandoned. The <em>wayyitnāḥēm</em> (and he was sorry, abandoned the plan) is the same verb used for YHWH's relenting — here applied to Saul's frustrated purpose.</p>",
    "14": "<p>David stays in wilderness strongholds (<em>mᵉṣûdôt</em>) in the hill country of Ziph. He is in the wilderness day by day, and Saul seeks him every day, but YHWH does not give him into his hand (<em>wᵉlōʾ nᵉtānô ʾĕlōhîm bᵉyādô</em>). The summary verse encapsulates the entire fugitive period's theology: Saul's relentless pursuit, David's daily danger, and YHWH's daily deliverance. The anointed is preserved through the wilderness by divine protection that operates invisibly — just as Jesus's many escapes from arrest in John's Gospel (7:30; 8:59; 10:39) reflect the same providential protection: <em>his hour had not yet come</em>.</p>",
    "15": "<p>David sees (<em>wayyarᵉ dāwid</em>) that Saul has come to seek his life at Horesh in the wilderness of Ziph. The fugitive's awareness of the approaching threat precedes any action. The sight of the pursuing king — at the moment of greatest danger — is immediately followed by Jonathan's arrival (v16). The juxtaposition is the narrative's signature of divine provision: the moment of maximum threat coincides with the arrival of maximum encouragement.</p>",
    "17": "<p>Jonathan's covenant renewal with David at Horesh: <em>ʾal-tîrāʾ kî lōʾ timṣāʾʾăḵā yad Šāʾûl ʾāḇî wᵉʾattāh timlōḵ ʿal yiśrāʾēl wᵉʾānōḵî ʾehyeh-lᵉḵā lᵉmišneh</em> — do not fear; for the hand of Saul my father shall not find you. You shall be king over Israel, and I shall be second to you. Jonathan's explicit acknowledgment — <em>you shall be king, I shall be second</em> — is the covenant surrender of his own succession rights. He yields what is his by birth to the anointed. John the Baptist makes this same surrender explicit: <em>He must increase, but I must decrease</em> (John 3:30). The one who holds the birthright by human order yields to the one anointed by divine choice.</p>",
    "18": "<p><em>wayyikrᵉtû šᵉnêhem bᵉrît lipnê YHWH</em> — and the two of them made a covenant before YHWH. This is the second or third covenant between David and Jonathan (18:3; 20:8; now 23:18). The covenant's renewal at the moment of David's greatest vulnerability reaffirms what was made at the court's height. Covenant made in prosperity and then reaffirmed in danger is the pattern of divine faithfulness: YHWH's covenant with Israel is renewed in the Sinai desert (Exod 19-24), in Moab before conquest (Deut), and in exile (Jer 31:31-34) — the new covenant made precisely when the old seems broken.</p>",
    "19": "<p>The Ziphites betray David to Saul: <em>wayyadᵉbîrû ʾel Šāʾûl baGiḇʿāh lēʾmōr hălōʾ Dāwid mistattēr ʿimānû bᵉmᵉṣûdôt baḥōrᵉšāh</em> — is not David hiding with us in the strongholds at Horesh? The Ziphites are Judeans — their own tribesmen betray the fugitive king. The betrayal from within the tribal community mirrors the betrayals in Jesus's ministry: his family thinks he is insane (Mark 3:21), his hometown rejects him (Luke 4:28-29), and a member of his inner circle betrays him (Matt 26:14-16).</p>",
    "20": "<p>The Ziphites offer to hand David over to Saul: <em>wᵉʿattāh kᵉḵol ʾāwen napšᵉḵā hammélek rᵉdat rēd ûlānû hammaśgîr bᵉyad hammélek</em> — now come down, O king, according to all your heart's desire to come down, and our part shall be to surrender him to the king's hand. The volunteered informing goes beyond required loyalty to active complicity. The Ziphites' offer mirrors those who volunteered to identify Jesus to the authorities (John 11:57) — official policy being implemented by the willing among the populace.</p>",
    "21": "<p>Saul's response: <em>bᵉrûḵîm ʾattem laYHWH kî ḥamaltem ʿālay</em> — blessed are you by YHWH because you have had compassion on me. The inverted blessing — invoking YHWH's name in gratitude for betrayal of the anointed — is a form of theological corruption. Saul uses YHWH-language for actions YHWH opposes. The persecution of God's anointed done in God's name is a recurring pattern: the Pharisees claim to honor Moses while rejecting the one Moses anticipated (John 5:45-46).</p>",
    "22": "<p>Saul instructs the Ziphites to confirm David's hiding places carefully: <em>wᵉdᵉʿû ûrᵉʾû ʾet mᵉqômô ʾăšer tihyeh raglô</em> — know and see the place where his foot is. The surveillance vocabulary — tracking the physical location of the fugitive — echoes throughout the passion narratives: the chief priests seeking the right time and place to seize Jesus (Luke 22:2), Judas providing the location of the garden (John 18:2).</p>",
    "23": "<p>Saul mobilizes a comprehensive search: <em>ûrᵉʾû wᵉhišmaʿtem ʾet kol hamᵉḥabbōʾîm</em> — take note of all the lurking places where he hides. The intelligence-gathering apparatus of the state directed against a single fugitive demonstrates how threatening the true anointed is to the false king. The more thorough the surveillance, the more complete the eventual failure — divine preservation outpaces human intelligence.</p>",
    "24": "<p>The Ziphites set out ahead of Saul. David and his men are in the wilderness of Maon (<em>bᵉmiḏbar Māʿôn bāʿărāḇāh ʾel yᵉmin hayyᵉšîmôn</em>). The geography shifts: from Horesh to Maon, the fugitive moves further into the desert. The desert wilderness as the location of the anointed's hiding and testing is the OT template for Jesus's forty-day wilderness testing (Matt 4:1) — the anointed proved in the wasteland before entering his public ministry.</p>",
    "25": "<p>Saul and his men go to search, and David hears: <em>wayyēreḏ hassela wayyēšeḇ bᵉmiḏbar Māʿôn</em> — David went down to the rock and dwelt in the wilderness of Maon. The topographic detail — David going down to the rock — carries typological resonance: the rock (<em>sela</em>) as divine refuge is the Psalms' signature metaphor for YHWH (Ps 18:2, 31, 46; 19:14; 62:2, 7). David literally lives in the rock that typologically expresses YHWH as refuge.</p>",
    "26": "<p>Saul goes on one side of the mountain while David and his men are on the other: <em>wayhî Šāʾûl hōlēḵ mizzeh hahār ûdāwid wᵉʾanāšāyw mizzeh hahār</em>. David is hurrying to escape, Saul is encircling him. <em>wayhî dāwid maḥîš lāleḵet mippᵉnê Šāʾûl</em> — David was hurrying. The noun <em>maḥîš</em> (hurrying) captures the urgency of the chase at its climax. The anointed's preservation through geography — the same mountain, opposite sides — is pure providential timing.</p>",
    "27": "<p>A messenger comes to Saul: <em>māhēr ûlēḵ kî pāšᵉṭû Pᵉlištîm ʿal hāʾāreṣ</em> — hurry and come, for the Philistines have raided the land. The Philistine raid that arrives at the exact moment of David's encirclement is the providential rescue — an external threat redirects the pursuer at the last possible moment. YHWH does not need to appear; he uses the ordinary mechanism of geopolitical emergency to preserve his anointed. The same pattern operates in the passion narrative's timing: events beyond anyone's control converge to accomplish the purposes of YHWH.</p>",
    "28": "<p>Saul withdraws from pursuing David to engage the Philistines: <em>wayyāšob Šāʾûl mirdōp ʾaḥărê dāwid wayyēlek liqraʾt Pᵉlištîm</em>. The place is named <em>Sela-hammahlekot</em> — the Rock of Division — because the king and David were divided there. The naming preserves the theological memory: YHWH divided the mountain between the pursuer and the pursued. The name is both geographical record and theological testimony.</p>",
    "29": "<p>David goes up from there and lives in the strongholds of En-gedi (<em>bᵉmᵉṣûdôt ʿEn Gedî</em>). The En-gedi wilderness — on the western shore of the Dead Sea — is among the most rugged terrain in the land, with springs and caves amidst sheer cliffs. The withdrawal to En-gedi is withdrawal to the strongest natural defensive position. The next scene (ch24) will place the pursuer and the pursued in the same cave at En-gedi — the reversal of the mountain-separation of v28 will become the cave-proximity that tests the anointed's restraint.</p>"
  },
  "24": {
    "1": "<p>Saul returns from the Philistine campaign and is told David is in the wilderness of En-gedi. The irony of the information exchange is subtle: Saul's spies report David's location immediately after YHWH's providential rescue at Sela-hammahlekot. The renewed pursuit — after divine intervention deflected it — demonstrates that the persecutor's intent is not reformed by failure. The repetition of the pursuit after the temporary grace recurs in John's Gospel: Jesus escapes repeated arrest attempts, each time returning to the same vulnerable proximity to his enemies.</p>",
    "2": "<p>Saul takes 3,000 chosen men from all Israel to seek David and his men on the rocks of the wild goats. The 3,000 elite warriors against David's 600 maintains the overwhelming force ratio of the entire fugitive narrative. The wild goat rocks (<em>ṣûrê hayyᵉʿēlîm</em>) are the terrain of the most agile animals — the fugitive king moves where armies cannot easily follow. The anointed in his weakness occupies the crags that power cannot easily reach.</p>",
    "3": "<p>Saul comes to the sheep pens by the road where there was a cave (<em>mᵉʿārāh</em>), and he enters to relieve himself (<em>lᵉhāsēḵ raglāyw</em>, lit. to cover his feet). David and his men are sitting in the innermost parts of the cave. The accidental entry of the enemy into the anointed's hiding place — for the most mundane biological reason — creates the scene of maximum temptation. Providence places the persecutor in the grasp of the persecuted. The king of Israel, unarmed and vulnerable, enters the cave of the one he hunts.</p>",
    "4": "<p>David's men urge him: <em>hinnēh hayyôm ʾăšer ʾāmar YHWH ʾēlêḵā hinnēh ʾānōḵî nōtēn ʾet ʾōyibᵉḵā bᵉyādeḵā</em> — behold the day of which YHWH said to you, &ldquo;I will give your enemy into your hand.&rdquo; Whether YHWH actually said this or whether the men are improvising a prophetic word to justify killing Saul is ambiguous. The temptation is framed in theological language — using YHWH's name to justify the seizure of what has not yet been properly given. The same temptation faces Jesus: the devil quotes Scripture to urge premature grasping of divine inheritance (Matt 4:6-7).</p>",
    "5": "<p>David cuts off the hem of Saul's robe (<em>wayyāqom dāwid wayyikrot ʾet kᵉnap hamᵉʿîl ʾăšer lᵉŠāʾûl ballāṭ</em>) — secretly, while Saul remains unaware. The <em>kānāp</em> (hem, wing) of the robe is symbolically significant: the robe represents royal authority; its hem could be used for sealing documents. When David later holds up the hem in v11, it proves proximity without bloodshed. But the cutting itself — even this small act — strikes David's conscience.</p>",
    "7": "<p>David restrains his men: <em>ḥālîlāh lî mēYHWH ʾim ʾeʿĕśeh ʾet haddāḇār hazzeh laʾdōnî limšîaḥ YHWH lišlōaḥ yādî bô kî mᵉšîaḥ YHWH hûʾ</em> — far be it from me before YHWH to do this thing to my lord, YHWH's anointed, to stretch out my hand against him, for he is YHWH's anointed. The repetition of <em>mᵉšîaḥ YHWH</em> — the LORD's anointed — twice in the restraint formula makes this the theological center of the En-gedi cave scene. David will not touch the LORD's anointed even though the anointed is his murderous persecutor. The ethic of non-retaliation against those whom YHWH has ordained — even when they pursue you unjustly — is the precise ethic of 1 Pet 2:23: <em>when he was reviled, he did not revile in return</em>.</p>",
    "8": "<p>David rebukes his men and does not let them attack Saul: <em>wayyišsaʿ dāwid ʾet ʾănāšāyw badᵉḇārîm</em> — David persuaded his men with words. The community of the anointed is held back from premature violence by the word of the anointed. The restraint extends from David to his followers — the non-retaliation ethic is not merely personal but communal. Jesus explicitly commands this for his disciples: <em>Put your sword back in its place</em> (Matt 26:52), restraining Peter's retaliatory strike at the arrest.</p>",
    "9": "<p>Saul exits the cave and David follows: <em>wayyāqom dāwid wayyēṣēʾ min hamᵉʿārāh wayyiqrāʾ ʾaḥărê Šāʾûl lēʾmōr ʾădōnî hammélek</em> — my lord the king! David calls to the departing Saul. The scene of the anointed calling after his persecutor — emerging from the cave, revealing his presence, demonstrating vulnerability — is an act of radical trust. He could have remained hidden; instead he shows himself. The willingness of the innocent to make themselves known to those who seek to destroy them is the posture of the cross: Jesus is not hidden when they come to arrest him in Gethsemane but says <em>ʾEgō eimi</em> — I am he (John 18:5).</p>",
    "10": "<p>David bows to the ground (<em>wayyiqod ʾerets wayyišteḥû</em>). He addresses Saul: <em>lāmmāh tišmaʿ ʾet diḇrê ʾādām lēʾmōr hinnēh dāwid mᵉḇaqqēš rāʿāteḵā</em> — why do you listen to the words of men saying, &ldquo;David seeks your harm&rdquo;? The address to the pursuer with prostration and direct correction — naming the slander and refusing to match it — demonstrates the non-retaliatory ethic in action. The anointed does not defend himself with equal violence but with truth, humility, and appeal to the evidence.</p>",
    "11": "<p>David shows the hem of Saul's robe: <em>rᵉʾēh kî ʾēt kᵉnap mᵉʿîlᵉḵā bᵉyādî</em> — look, the hem of your robe is in my hand. The physical evidence of the opportunity not taken — the proof that he could have killed but did not — is the testimony that verbal claims cannot equal. <em>kî bᵉkārᵉtî ʾet kᵉnap mᵉʿîlᵉḵā wᵉlōʾ hăragutiḵā dāʿ ûrᵉʾēh kî ʾên bᵉyādî rāʿāh ûpešaʿ wᵉlōʾ ḥāṭāʾtî lāḵ</em> — in cutting the hem of your robe and not killing you, know and see that there is no evil or treason in my hand, and I have not sinned against you. The evidence of self-restraint is greater than any oath.</p>",
    "12": "<p><em>YHWH yišpoṭ bênî ûḇênêḵā ûnᵉqāmanî YHWH mimmennu ûyādî lōʾ tihyeh bāḵ</em> — may YHWH judge between me and you; may YHWH avenge me against you, but my hand shall not be against you. The appeal to YHWH as judge rather than taking personal vengeance is the OT's clearest statement of the retribution-to-God principle. Romans 12:19 quotes Deut 32:35 in the same vein: <em>vengeance is mine, I will repay</em>. David models what Paul commands: bless the persecutor, do not avenge yourself, let YHWH be the judge.</p>",
    "13": "<p><em>kaʾăšer yōʾmar mᵉšal haqqadmōnî mērᵉšāʿîm yēṣēʾ rešaʿ ûyādî lōʾ tihyeh bāḵ</em> — as the ancient proverb says, &ldquo;Out of the wicked comes wickedness,&rdquo; but my hand shall not be against you. The appeal to proverbial wisdom grounds the non-violence in folk wisdom as well as theology. The actions proceed from the character of the actor: from the wicked, wickedness; from the anointed who refuses wickedness, the evidence will speak itself.</p>",
    "14": "<p>David asks: <em>ʾaḥar mî yāṣāʾ melek yiśrāʾēl ʾaḥar mî ʾattāh rōdēp</em> — after whom has the king of Israel come out? After whom do you pursue? <em>ʾaḥar keleb mēt ʾaḥar parʿōš ʾeḥāt</em> — after a dead dog! After a single flea! The self-deprecation is rhetorical but also genuinely humble: David does not inflate his own threat. The disproportion of the king's military campaign against one fugitive is highlighted through the dead-dog and flea imagery. Jesus's silence before Pilate and Herod has the same structural quality: the greatest threat the authorities imagined was in fact the most humble figure they had ever encountered.</p>",
    "16": "<p>Saul's response: <em>qôlᵉḵā bᵉnî dāwid wayyissā Šāʾûl qōlô wayyēḇĕ</em> — is this your voice, my son David? And Saul wept. The persecutor, confronted with the evidence of the anointed's restraint and non-retaliation, weeps. The hard heart is momentarily softened by the sight of mercy. Saul's weeping is genuine but not lasting — it produces temporary remorse without lasting repentance, like Esau's weeping (Heb 12:17) or Judas's remorse (Matt 27:3-5). The tears of the momentarily convicted are not the repentance of the renewed.</p>",
    "17": "<p>Saul confesses: <em>ṣaddîq ʾattāh mimmennî kî ʾattāh gᵉmaltanî haṭṭôḇāh wᵉʾānōḵî gᵉmaltîḵā hārāʿāh</em> — you are more righteous than I, for you have repaid me good and I have repaid you evil. The explicit acknowledgment of the anointed's righteousness and his own wickedness from the mouth of the persecutor is the En-gedi scene's theological climax. The evidence of the unretaliating anointed produces confession from the persecutor. The NT equivalent: the centurion at the cross — <em>truly this was the Son of God</em> (Matt 27:54), the persecutors' representative confessing what the resurrection will vindicate.</p>",
    "18": "<p><em>wᵉʾattāh higgadtā ʾēt ʾăšer ʿāśîtā lî ṭōḇāh ʾēt ʾăšer sᵉgāranî YHWH bᵉyādeḵā wᵉlōʾ hᵉragātnî</em> — you have declared today what good you have done to me, that YHWH gave me into your hand and you did not kill me. Saul explicitly names what David did: YHWH gave the persecutor into the anointed's hand, and the anointed let him go. The king acknowledges that his survival depends entirely on the mercy of the one he pursues.</p>",
    "19": "<p><em>wᵉkî yimṣā ʾîš ʾet ʾōyibô ûšilᵉḥô bᵉdereḵ ṭôḇāh wᵉYHWH yᵉšallimᵉḵā ṭôḇāh taḥat hayyôm hazzeh ʾăšer ʿāśîtā lî</em> — for if a man finds his enemy and sends him away on the good road, may YHWH reward you with good for what you did to me today. Saul provides the theological interpretation of David's act: sending an enemy on the good way is the proper response to mercy. <em>YHWH yᵉšallimᵉḵā</em> — may YHWH repay you — is an implicit recognition that the ultimate repayment belongs to YHWH, not to Saul.</p>",
    "20": "<p>Saul's prophetic acknowledgment: <em>wᵉʿattāh yādaʿtî kî mālōḵ timlōḵ ûqāmāh bᵉyādᵉḵā mamleket yiśrāʾēl</em> — I know that you shall surely be king, and that the kingdom of Israel shall be established in your hand. The persecutor confesses the anointed's destiny from his own mouth. Pilate's inscription — <em>Yeshua of Nazareth, King of the Jews</em> (John 19:19) — is Saul's confession restaged: the authority that prosecutes the anointed inadvertently testifies to his kingship.</p>",
    "21": "<p>Saul asks David to swear: <em>wᵉʿattāh hišābaʿ lî baYHWH ʾim tašmîd ʾet zarʿî ʾaḥărāy wᵉʾim tašmîd ʾet šᵉmî mibêt ʾāḇî</em> — swear to me by YHWH that you will not cut off my descendants and that you will not destroy my name from my father's house. Saul's request — preserve my family even when you have the power to destroy them — is the practical application of his confession. He knows the pattern of new dynasties eliminating rival claimants. His fear is theologically informed: the messianic king will be defined by his mercy.</p>",
    "22": "<p>David swears to Saul, and Saul goes home while David and his men go up to the stronghold. The covenant of mercy between the persecutor and the persecuted is made on the basis of the anointed's demonstrated restraint. David's later preservation of Mephibosheth (2 Sam 9) fulfills this oath. Jesus's preservation of all given to him by the Father (John 17:12; 18:9) is the ultimate fulfillment: <em>those whom you gave me I have kept, and none of them is lost</em>.</p>"
  }
}

if __name__ == "__main__":
    comm = load_comm("mkt-christ", "1samuel")
    merge_comm(comm, SAM1)
    save_comm("mkt-christ", "1samuel", comm)
    print("Done. Verifying ch22-24...")
    import json as _j
    result = _j.loads((ROOT / "data/commentary/mkt-christ/1samuel.json").read_text())
    with open(ROOT / "data/interlinear/1samuel.json") as f:
        inter = _j.load(f)
    for ch in ["22", "23", "24"]:
        il_vv = set(inter[ch].keys())
        out_vv = set(result.get(ch, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f"  ch{ch}: STILL MISSING {sorted(missing, key=int)}")
        else:
            print(f"  ch{ch}: complete ({len(out_vv)} verses)")
